package main

import "fmt"

type Storer interface {
	Store(key, value string)
}

type Retriever interface {
	Retrieve(key string) string
}

type Saver interface {
	Storer
	Retriever
}

type MemoryStore struct {
	data map[string]string
}

func (m *MemoryStore) Store(key, value string) {
	if m.data == nil {
		m.data = make(map[string]string)
	}
	m.data[key] = value
}

func (m *MemoryStore) Retrieve(key string) string {
	return m.data[key]
}

func saveAndGet(s Saver, key, value string) {
	s.Store(key, value)
	fmt.Println(s.Retrieve(key))
}

func main() {
	store := &MemoryStore{}
	saveAndGet(store, "name", "Alex")
	saveAndGet(store, "city", "London")
}

